import pathlib, re

root = pathlib.Path(r'd:\code\investing\light-weight-main')

catalog_path = root / 'indicators' / 'catalog.py'
catalog = catalog_path.read_text(encoding='utf-8')
catalog = catalog.replace('{"name": "line", "label": "Garis Pattern", "default": "#f8fafc"},', '{"name": "line", "label": "Garis Pattern", "default": "#1d4ed8"},')
catalog = re.sub(r'if indicator_key == "CANDLE_PATTERN":\n\s+return "Candle Pattern"', 'if indicator_key == "CANDLE_PATTERN":\n        return f"Candle Pattern {params[\'lookback\']}"', catalog)
catalog_path.write_text(catalog, encoding='utf-8')

candle_path = root / 'indicators' / 'candle_patterns.py'
candle = candle_path.read_text(encoding='utf-8')
candle = re.sub(
    r'\n\s+recent_events = events\.tail\(24\)\.copy\(\)[\s\S]*?\n\s+return \{\n\s+"events": event_rows,\n\s+"latest_by_direction": latest_by_direction,\n\s+"total_events": int\(len\(events\)\),\n\s+\}',
    '''\n    formatted_events = events.copy()\n    formatted_events["date_label"] = formatted_events["time"].map(format_short_date_label)\n    event_rows = [\n        {\n            "time": row.time,\n            "date_label": row.date_label,\n            "pattern_key": row.pattern_key,\n            "label": row.label,\n            "short_label": row.short_label,\n            "description": row.description,\n            "direction": row.direction,\n        }\n        for row in formatted_events.itertuples(index=False)\n    ]\n\n    latest_by_direction: dict[str, dict[str, Any]] = {}\n    for direction in ["bullish", "bearish", "neutral"]:\n        direction_events = formatted_events.loc[formatted_events["direction"] == direction]\n        if direction_events.empty:\n            continue\n        latest = direction_events.iloc[-1]\n        latest_by_direction[direction] = {\n            "label": str(latest["label"]),\n            "short_label": str(latest["short_label"]),\n            "description": str(latest["description"]),\n            "date_label": format_short_date_label(latest["time"]),\n        }\n\n    return {\n        "events": event_rows,\n        "latest_by_direction": latest_by_direction,\n        "total_events": int(len(events)),\n    }''',
    candle,
    count=1,
)
candle_path.write_text(candle, encoding='utf-8')

chart_pattern_path = root / 'indicators' / 'chart_patterns.py'
chart_pattern = chart_pattern_path.read_text(encoding='utf-8')
chart_pattern = chart_pattern.replace('    candidates.sort(key=lambda item: item["end_time"])\n    return candidates[-12:]', '    candidates.sort(key=lambda item: item["end_time"])\n    return candidates')
chart_pattern_path.write_text(chart_pattern, encoding='utf-8')

chart_service_path = root / 'charts' / 'chart_service.py'
chart_service = chart_service_path.read_text(encoding='utf-8')
chart_service = chart_service.replace('    "line": "#f8fafc",', '    "line": "#1d4ed8",')
chart_service = re.sub(
    r'def _render_candle_patterns\(chart: Any, data: pd\.DataFrame, indicator: dict\[str, Any\]\) -> None:[\s\S]*?\n\ndef _render_chart_patterns',
    '''def _render_candle_patterns(chart: Any, data: pd.DataFrame, indicator: dict[str, Any]) -> None:\n    """Render detected candle-pattern labels directly on the main chart."""\n    colors = _indicator_colors(indicator)\n    events = detect_candle_patterns(data, indicator.get("params") or {})\n    if events.empty:\n        return\n\n    marker_points: list[dict[str, Any]] = []\n    markers: list[dict[str, Any]] = []\n    series_name = "Candle Pattern"\n    for row in events.itertuples(index=False):\n        direction = str(row.direction)\n        marker_points.append({"time": row.time, series_name: float(row.price)})\n        markers.append(\n            {\n                "time": row.time,\n                "position": str(row.position),\n                "shape": "square",\n                "color": colors.get(direction, CANDLE_PATTERN_COLORS.get(direction, "#f8fafc")),\n                "text": str(row.short_label),\n            }\n        )\n\n    _render_text_marker_series(chart, series_name, marker_points, markers)\n\n\ndef _render_chart_patterns''',
    chart_service,
    count=1,
)
chart_service = re.sub(
    r'def _render_chart_patterns\(chart: Any, data: pd\.DataFrame, indicator: dict\[str, Any\]\) -> None:[\s\S]*?\n\ndef _render_overlay_indicator',
    '''def _render_chart_patterns(chart: Any, data: pd.DataFrame, indicator: dict[str, Any]) -> None:\n    """Render detected chart patterns as guide lines and compact labels."""\n    colors = _indicator_colors(indicator)\n    patterns = detect_chart_patterns(data, indicator.get("params") or {})\n    if not patterns:\n        return\n\n    marker_points: list[dict[str, Any]] = []\n    markers: list[dict[str, Any]] = []\n    series_name = "Chart Pattern"\n    line_base_color = colors.get("line", CHART_PATTERN_COLORS["line"])\n\n    for pattern in patterns:\n        direction = str(pattern.get("direction") or "neutral")\n        tone_color = colors.get(direction, CHART_PATTERN_COLORS.get(direction, line_base_color))\n        pattern_points = pattern.get("points") or []\n        for point_start, point_end in zip(pattern_points, pattern_points[1:]):\n            chart.trend_line(\n                start_time=point_start["time"],\n                start_value=float(point_start["price"]),\n                end_time=point_end["time"],\n                end_value=float(point_end["price"]),\n                line_color=_with_alpha(line_base_color, 0.72),\n                width=2,\n                style="solid",\n            )\n        for line in pattern.get("lines") or []:\n            chart.trend_line(\n                start_time=line["start_time"],\n                start_value=float(line["start_value"]),\n                end_time=line["end_time"],\n                end_value=float(line["end_value"]),\n                line_color=_with_alpha(line_base_color, 0.96),\n                width=2,\n                style="solid",\n            )\n\n        marker_points.append({"time": pattern["label_time"], series_name: float(pattern["label_price"])})\n        markers.append(\n            {\n                "time": pattern["label_time"],\n                "position": "below" if direction == "bullish" else "above",\n                "shape": "square",\n                "color": tone_color,\n                "text": str(pattern["short_label"]),\n            }\n        )\n\n    _render_text_marker_series(chart, series_name, marker_points, markers)\n\n\ndef _render_overlay_indicator''',
    chart_service,
    count=1,
)
chart_service = re.sub(
    r'def _render_backtest_trade_markers\(chart: Any, trade_log: pd\.DataFrame \| None\) -> None:[\s\S]*?if not marker_points:',
    '''def _render_backtest_trade_markers(chart: Any, trade_log: pd.DataFrame | None) -> None:\n    """Render buy and sell labels on the main price chart for completed trades."""\n    if trade_log is None or trade_log.empty:\n        return\n\n    marker_points: list[dict[str, Any]] = []\n    markers: list[dict[str, Any]] = []\n    for row in trade_log.itertuples(index=False):\n        entry_time = getattr(row, "entry_datetime", None)\n        entry_price = getattr(row, "entry_price", None)\n        if entry_time is not None and entry_price is not None:\n            marker_points.append({"time": entry_time, "Backtest Signal": float(entry_price)})\n            markers.append(\n                {\n                    "time": entry_time,\n                    "position": "below",\n                    "shape": "circle",\n                    "color": "#22c55e",\n                    "text": "Buy",\n                }\n            )\n\n        exit_time = getattr(row, "exit_datetime", None)\n        exit_price = getattr(row, "exit_price", None)\n        if exit_time is not None and exit_price is not None:\n            marker_points.append({"time": exit_time, "Backtest Signal": float(exit_price)})\n            markers.append(\n                {\n                    "time": exit_time,\n                    "position": "above",\n                    "shape": "circle",\n                    "color": "#ef4444",\n                    "text": "Sell",\n                }\n            )\n\n    if not marker_points:''',
    chart_service,
    count=1,
)
chart_service_path.write_text(chart_service, encoding='utf-8')

market_path = root / 'ui' / 'market_insight.py'
market = market_path.read_text(encoding='utf-8')
market = re.sub(
    r'PATTERN_DIRECTION_LABELS = \{[\s\S]*?def render_indicator_explanation_card',
    '''PATTERN_DIRECTION_LABELS = {\n    "bullish": "Bullish",\n    "bearish": "Bearish",\n    "neutral": "Netral",\n}\n\n\ndef format_pattern_direction_label(direction: str) -> str:\n    """Translate one pattern direction into Indonesian display text."""\n    normalized_direction = str(direction or "").strip().lower()\n    return PATTERN_DIRECTION_LABELS.get(normalized_direction, normalized_direction or "-")\n\n\ndef build_indicator_note_table_html(\n    title: str,\n    columns: list[str],\n    rows: list[list[str]],\n) -> str:\n    """Build one compact HTML table for indicator history rows."""\n    if not rows:\n        return ""\n\n    header_html = "".join(\n        f'<th style="padding: 0.72rem 0.78rem; text-align: left; background: rgba(15, 23, 42, 0.92); color: #cbd5e1; font-size: 0.84rem; font-weight: 700; border-bottom: 1px solid rgba(148, 163, 184, 0.18); white-space: nowrap;">{html.escape(column)}</th>'\n        for column in columns\n    )\n\n    body_rows: list[str] = []\n    for row_index, row_values in enumerate(rows):\n        row_background = "rgba(15, 23, 42, 0.34)" if row_index % 2 == 0 else "rgba(15, 23, 42, 0.22)"\n        cell_html = "".join(\n            f'<td style="padding: 0.72rem 0.78rem; color: #e2e8f0; font-size: 0.84rem; border-top: 1px solid rgba(148, 163, 184, 0.10); vertical-align: top;">{html.escape(str(cell_value))}</td>'\n            for cell_value in row_values\n        )\n        body_rows.append(f'<tr style="background: {row_background};">{cell_html}</tr>')\n\n    return (\n        '<div style="margin-top: 1rem;">'\n        f'<div class="indicator-note-section-context">{html.escape(title)}</div>'\n        '<div style="overflow-x: auto; border: 1px solid rgba(148, 163, 184, 0.16); border-radius: 14px; background: rgba(15, 23, 42, 0.24);">'\n        '<table style="width: 100%; border-collapse: collapse; min-width: 720px;">'\n        f'<thead><tr>{header_html}</tr></thead>'\n        f'<tbody>{"".join(body_rows)}</tbody>'\n        '</table></div></div>'\n    )\n\n\ndef build_indicator_note_section_html(\n    title: str,\n    summary_text: str,\n    boxes_html: list[str],\n    context_text: str = "",\n    extra_html: str = "",\n) -> str:\n    """Build one section inside the indicator explanation card."""\n    context_html = (\n        f'<div class="indicator-note-section-context">{html.escape(context_text)}</div>'\n        if context_text\n        else ""\n    )\n    return (\n        '<div class="indicator-note-section">'\n        f'<div class="indicator-note-section-title">{html.escape(title)}</div>'\n        f'<div class="indicator-note-section-summary">{html.escape(summary_text)}</div>'\n        f"{context_html}"\n        f'<div class="indicator-note-grid">{"".join(boxes_html)}</div>'\n        f"{extra_html}"\n        "</div>"\n    )\n\n\ndef render_indicator_explanation_card''',
    market,
    count=1,
)
market = re.sub(
    r'if indicator_key == "CANDLE_PATTERN":[\s\S]*?if indicator_key == "CONSOLIDATION_AREA":',
    '''if indicator_key == "CANDLE_PATTERN":\n            summary = summarize_candle_patterns(result.data, params)\n            bullish_color = colors.get("bullish", "#22c55e")\n            bearish_color = colors.get("bearish", "#ef4444")\n            neutral_color = colors.get("neutral", "#f8fafc")\n            latest_event = summary["events"][-1] if summary["events"] else None\n            latest_bullish = summary["latest_by_direction"].get("bullish")\n            latest_bearish = summary["latest_by_direction"].get("bearish")\n            latest_neutral = summary["latest_by_direction"].get("neutral")\n            candle_history_table_html = build_indicator_note_table_html(\n                title="Daftar semua candle pattern di chart",\n                columns=["Tanggal", "Kode", "Pattern", "Arah", "Keterangan"],\n                rows=[\n                    [\n                        str(event["date_label"]),\n                        str(event["short_label"]),\n                        str(event["label"]),\n                        format_pattern_direction_label(str(event["direction"])),\n                        str(event["description"]),\n                    ]\n                    for event in reversed(summary["events"])\n                ],\n            )\n            if latest_event is None:\n                section_html.append(\n                    build_indicator_note_section_html(\n                        title="Candle Pattern",\n                        summary_text="Belum ada pola candle yang cocok di range chart aktif.",\n                        context_text=f"Lookback {int(params['lookback'])} candle. Centang pola tertentu di editor untuk menyembunyikan label yang tidak ingin kamu lihat.",\n                        boxes_html=[\n                            build_indicator_note_info_box_html(\n                                label="Pattern Terbaru",\n                                value=None,\n                                color=neutral_color,\n                                empty_message="Belum ada pattern candle yang cocok di range ini.",\n                            ),\n                            build_indicator_note_info_box_html(\n                                label="Bullish Terbaru",\n                                value=None,\n                                color=bullish_color,\n                                empty_message="Belum ada pattern bullish.",\n                            ),\n                            build_indicator_note_info_box_html(\n                                label="Bearish Terbaru",\n                                value=None,\n                                color=bearish_color,\n                                empty_message="Belum ada pattern bearish.",\n                            ),\n                        ],\n                    )\n                )\n                continue\n\n            section_html.append(\n                build_indicator_note_section_html(\n                    title="Candle Pattern",\n                    summary_text=(\n                        f"Pattern candle terbaru adalah {latest_event['label']} pada {latest_event['date_label']}. "\n                        f"Total pola yang terdeteksi di range ini: {int(summary['total_events'])}."\n                    ),\n                    context_text=f"Lookback {int(params['lookback'])} candle. Label singkat seperti BE, BU, dan DJ tampil langsung di chart utama.",\n                    boxes_html=[\n                        build_indicator_note_info_box_html(\n                            label="Pattern Terbaru",\n                            value=str(latest_event["label"]),\n                            color=(\n                                bullish_color if latest_event["direction"] == "bullish"\n                                else bearish_color if latest_event["direction"] == "bearish"\n                                else neutral_color\n                            ),\n                            detail_lines=[\n                                f"Tanggal {latest_event['date_label']}",\n                                str(latest_event["description"]),\n                            ],\n                        ),\n                        build_indicator_note_info_box_html(\n                            label="Bullish Terbaru",\n                            value=(str(latest_bullish["label"]) if latest_bullish else None),\n                            color=bullish_color,\n                            detail_lines=(\n                                [\n                                    f"Tanggal {latest_bullish['date_label']}",\n                                    str(latest_bullish["description"]),\n                                ]\n                                if latest_bullish\n                                else None\n                            ),\n                            empty_message="Belum ada pattern bullish di range ini.",\n                        ),\n                        build_indicator_note_info_box_html(\n                            label="Bearish Terbaru",\n                            value=(str(latest_bearish["label"]) if latest_bearish else None),\n                            color=bearish_color,\n                            detail_lines=(\n                                [\n                                    f"Tanggal {latest_bearish['date_label']}",\n                                    str(latest_bearish["description"]),\n                                ]\n                                if latest_bearish\n                                else None\n                            ),\n                            empty_message="Belum ada pattern bearish di range ini.",\n                        ),\n                        build_indicator_note_info_box_html(\n                            label="Netral Terbaru",\n                            value=(str(latest_neutral["label"]) if latest_neutral else None),\n                            color=neutral_color,\n                            detail_lines=(\n                                [\n                                    f"Tanggal {latest_neutral['date_label']}",\n                                    str(latest_neutral["description"]),\n                                ]\n                                if latest_neutral\n                                else None\n                            ),\n                            empty_message="Belum ada pattern netral di range ini.",\n                        ),\n                    ],\n                    extra_html=candle_history_table_html,\n                )\n            )\n            continue\n\n        if indicator_key == "CHART_PATTERN":\n            summary = summarize_chart_patterns(result.data, params)\n            bullish_color = colors.get("bullish", "#22c55e")\n            bearish_color = colors.get("bearish", "#ef4444")\n            neutral_color = colors.get("neutral", "#38bdf8")\n            latest_pattern = summary["patterns"][-1] if summary["patterns"] else None\n            latest_bullish = summary["latest_by_direction"].get("bullish")\n            latest_bearish = summary["latest_by_direction"].get("bearish")\n            latest_neutral = summary["latest_by_direction"].get("neutral")\n            chart_history_table_html = build_indicator_note_table_html(\n                title="Daftar semua chart pattern di chart",\n                columns=["Tanggal", "Kode", "Pattern", "Arah", "Keterangan"],\n                rows=[\n                    [\n                        str(pattern["date_label"]),\n                        str(pattern["short_label"]),\n                        str(pattern["label"]),\n                        format_pattern_direction_label(str(pattern["direction"])),\n                        " | ".join([str(pattern["description"]), *[str(line) for line in pattern.get("detail_lines") or []]]),\n                    ]\n                    for pattern in reversed(summary["patterns"])\n                ],\n            )\n            if latest_pattern is None:\n                section_html.append(\n                    build_indicator_note_section_html(\n                        title="Chart Pattern",\n                        summary_text="Belum ada chart pattern besar yang cocok di range chart aktif.",\n                        context_text=(\n                            f"Lookback {int(params['lookback'])} candle, pivot {int(params['pivot_window'])}, "\n                            f"toleransi harga {int(params['tolerance_pct'])}%."\n                        ),\n                        boxes_html=[\n                            build_indicator_note_info_box_html(\n                                label="Pattern Terbaru",\n                                value=None,\n                                color=neutral_color,\n                                empty_message="Belum ada chart pattern yang cocok di range ini.",\n                            ),\n                            build_indicator_note_info_box_html(\n                                label="Bullish Terbaru",\n                                value=None,\n                                color=bullish_color,\n                                empty_message="Belum ada chart pattern bullish.",\n                            ),\n                            build_indicator_note_info_box_html(\n                                label="Bearish Terbaru",\n                                value=None,\n                                color=bearish_color,\n                                empty_message="Belum ada chart pattern bearish.",\n                            ),\n                        ],\n                    )\n                )\n                continue\n\n            section_html.append(\n                build_indicator_note_section_html(\n                    title="Chart Pattern",\n                    summary_text=(\n                        f"Chart pattern terbaru adalah {latest_pattern['label']} pada {latest_pattern['date_label']}. "\n                        f"Total pola yang terbaca: {int(summary['total_patterns'])}."\n                    ),\n                    context_text=(\n                        f"Lookback {int(params['lookback'])} candle, pivot {int(params['pivot_window'])}, "\n                        f"toleransi harga {int(params['tolerance_pct'])}%. Label singkat tampil di chart utama dan garis pola digambar otomatis."\n                    ),\n                    boxes_html=[\n                        build_indicator_note_info_box_html(\n                            label="Pattern Terbaru",\n                            value=str(latest_pattern["label"]),\n                            color=(\n                                bullish_color if latest_pattern["direction"] == "bullish"\n                                else bearish_color if latest_pattern["direction"] == "bearish"\n                                else neutral_color\n                            ),\n                            detail_lines=[\n                                f"Tanggal {latest_pattern['date_label']}",\n                                str(latest_pattern["description"]),\n                                *[str(line) for line in latest_pattern.get("detail_lines") or []][:2],\n                            ],\n                        ),\n                        build_indicator_note_info_box_html(\n                            label="Bullish Terbaru",\n                            value=(str(latest_bullish["label"]) if latest_bullish else None),\n                            color=bullish_color,\n                            detail_lines=(\n                                [\n                                    f"Tanggal {latest_bullish['date_label']}",\n                                    str(latest_bullish["description"]),\n                                    *[str(line) for line in latest_bullish.get("detail_lines") or []][:2],\n                                ]\n                                if latest_bullish\n                                else None\n                            ),\n                            empty_message="Belum ada chart pattern bullish di range ini.",\n                        ),\n                        build_indicator_note_info_box_html(\n                            label="Bearish Terbaru",\n                            value=(str(latest_bearish["label"]) if latest_bearish else None),\n                            color=bearish_color,\n                            detail_lines=(\n                                [\n                                    f"Tanggal {latest_bearish['date_label']}",\n                                    str(latest_bearish["description"]),\n                                    *[str(line) for line in latest_bearish.get("detail_lines") or []][:2],\n                                ]\n                                if latest_bearish\n                                else None\n                            ),\n                            empty_message="Belum ada chart pattern bearish di range ini.",\n                        ),\n                        build_indicator_note_info_box_html(\n                            label="Netral Terbaru",\n                            value=(str(latest_neutral["label"]) if latest_neutral else None),\n                            color=neutral_color,\n                            detail_lines=(\n                                [\n                                    f"Tanggal {latest_neutral['date_label']}",\n                                    str(latest_neutral["description"]),\n                                    *[str(line) for line in latest_neutral.get("detail_lines") or []][:2],\n                                ]\n                                if latest_neutral\n                                else None\n                            ),\n                            empty_message="Belum ada chart pattern netral di range ini.",\n                        ),\n                    ],\n                    extra_html=chart_history_table_html,\n                )\n            )\n            continue\n\n        if indicator_key == "CONSOLIDATION_AREA":''',
    market,
    count=1,
)
market_path.write_text(market, encoding='utf-8')

print('prepared')
